css:
// esconder categorias
#c-64ec4f8d2cd6b659592edb20 {
  display: none !important;
}

.checkout__app .recommended-items,
.checkout__btn-offers {
  display: none !important;
}

.search-engine__filter--pacote_com,
.search-engine__filter--Categories,
.search-engine__filter--Brands,
.search-engine__filter--forminhas,
.search-engine__filter--composicao_da_caixa,
.search-engine__filter--modelo_da_caixa,
.search-engine__filter--ean {
  display: none !important;
}

#search-bar {
  display: block !important;
}

.buy-together__item .product-card__buy {
  display: none !important;
}

.buy-together__title {
  position: relative;
  color: #37b8f8;
  font-family: quicksand;
  line-height: 1.22;
  text-decoration: none;
  margin-bottom: 1.25rem;

  > div {
    padding: 0 var(--spacer-3);
    margin: 0 auto;
    display: inline-block;
    background: #fff;
    font-size: 1.375rem;
    font-weight: 700;
    z-index: 2;
    position: relative;
  }

  &::before {
    background: var(--border-color);
    content: " ";
    height: var(--border-width);
    left: 15%;
    margin-top: -0.05rem;
    position: absolute;
    top: 50%;
    width: 70%;
  }
}

.dynamic-showcase {
  min-height: 500px;
}

@media (min-width: 992px) {
  .glide__bullets {
    bottom: 1.75rem;
    display: none;
  }
}

#header {
  background-color: #fff !important;
  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15) !important;
  border-width: 0;
  padding: 0;
}

.header__row {
  padding-left: 15px;
  padding-right: 15px;
}

.header__row .header__nav a {
  padding-right: 1rem;
  font-weight: 600;
  color: #333;
}

.top-bar__nav,
.top-bar {
  background: #fff;
}

.top-bar__page-links {
  font-size: 0.6rem;
  float: right;
  margin-right: -20px;
  text-transform: uppercase;
}

.top-bar__nav {
  display: none !important;
}

body {
  font-family: "Quicksand", sans-serif;
  font-size: 1rem;
  font-weight: 400;
  line-height: 1.68;
  color: #6a6a57;
}

#search-input {
  font-size: 12px !important;
  text-transform: initial !important;
  font-weight: 400 !important;
  border: 1px dashed #4698ca !important;
  border-radius: 10px;
  font-family: quicksand;
  background: #fff;
}

.header__buttons .btn,
.header__search-btn .fa-search {
  color: #4698ca;
}

h1 {
  font-size: 2rem !important;
  color: #76574b;
  font-family: quicksand;
  font-weight: 700;
  line-height: 1.22;
}

.blog-post a {
  color: #bb8e40;
  text-decoration: revert;
}

blockquote {
  margin: 0 20px;
  font-style: italic;
}

.hero-banner {
  margin: 0;
}

.payment__badges {
  display: none;
}

.discount-applier .alert::after {
  content: "*O valor do desconto não é cumulativo com outras promoções";
}

.cart__summary-row[data-discount^="0.0"],
.summary__amount__row[data-discount^="0.0"] {
  display: none;
}

.order-info__status--open {
  display: none;
}

.summary__item img {
  width: 50px;
}

.info-bar {
  background: #37b8f8;
  color: #fff;
  width: 100%;
}

.info-bar__title {
  font-weight: bold;
}

.info-bar__text {
  text-transform: initial;
  font-size: 16px;
}

.rounded-icon {
  border: 1px solid #4698ca;
}

.collection-shelf {
  margin-top: 1rem;
}

/* Botões / cards */
.product-card span {
  text-align: center;
}

.product-card__buy.fade {
  opacity: 1 !important;
}

.product-card .product-card__buy {
  opacity: 1 !important;
  position: relative;
  top: auto;
  margin: 0;
  bottom: auto;
  left: auto;
  transform: unset;
  background: transparent !important;
  display: flex;
  align-items: center;
  gap: 15px;
}

.product-card__buy {
  margin-top: 1rem !important;
}

.product-card__buy .btn-primary {
  padding: 0;
  width: auto;
  min-width: unset;
  line-height: 36px;
  font-size: 0.8rem;
  background-color: #162567;
  border-color: #162567;
}

.product-card__buy .btn-primary div {
  padding: 0 15px;
}

.product-card__buy .fas {
  display: none;
}

.btn-primary {
  background-color: rgb(40, 167, 69);
  border-color: rgb(40, 167, 69);
  padding: 0.5rem 5rem;
}

/* carrinho vitrine inteligente */
.cart .row .col-md-7 {
  display: flex;
  flex-direction: column;
}

.cart .row .col-md-7 .cart__list {
  order: -1;
}

.cart .row .col-md-7 .cart__back {
  order: 2;
}

.cart .row .col-md-7 .recommended-items {
  order: 3;
}

.cart__list + .recommended-items .recommended-items__title .lead {
  font-size: 0;
}

.cart__list + .recommended-items .recommended-items__title .lead::after {
  font-size: 25px !important;
  color: #37b8f8 !important;
  content: "Que tal aproveitar o frete?";
}

/* quantity selector */
.product__buy .apx_quantity_selector {
  position: relative;
}

.product__buy .apx_quantity_selector button:last-child {
  left: auto;
  right: 0;
}

.product__buy .apx_quantity_selector button i {
  font-size: 12px;
  line-height: 32px;
}

.product__buy .apx_quantity_selector button {
  background: transparent;
  border: 0;
  border-radius: 7px;
  color: #333;
  height: 34px;
  left: 0;
  margin: 7px;
  position: absolute;
  text-align: center;
  top: 0;
  width: 34px;
  z-index: 2;
}

.product__buy .apx_quantity_selector input {
  background: #f7f7f7;
  border: 0;
  border-radius: 5px;
  font-size: 18px;
  height: 48px;
  letter-spacing: 1px;
  pointer-events: none;
  text-align: center;
  width: 120px;
  font-weight: bold;
}

/* redes/pagamento ocultos */
.share-network-facebook,
.share-network-whatsapp,
.share-network-twitter,
.share-network-telegram,
.share-network-pinterest,
.share-network-email,
.share-network-sms,
.product__payment.card {
  display: none;
}

/* bloco sobre nós */
.sobre_cell_title h4 {
  margin-bottom: 20px;
  font: normal normal 400 30px/40px quicksand;
  letter-spacing: 0;
  color: #37b8f8;

  &::after {
    content: "";
    background: #eee;
    height: 1px;
    width: 100%;
    display: block;
  }

  span {
    border-bottom: 2px solid #37b8f8;
  }
}

.sobre_cell_text {
  display: flex;
  flex-direction: column;

  h5 {
    font: normal normal bold 20px/40px quicksand;
    letter-spacing: 0;
    color: #333;
    margin: 20px 0;
  }

  p {
    font: normal normal 300 18px/36px quicksand;
    letter-spacing: 0;
    color: #333;
    margin-bottom: 30px;
  }

  a {
    background: #4698ca;
    border-radius: 50px;
    font: normal normal bold 18px/40px quicksand;
    letter-spacing: 0;
    color: #fff;
    text-transform: uppercase;
    padding: 5px 110px;
    width: 60%;
  }
}

.sobre_cell_video {
  .celltronics-mobileonly {
    display: none;
    background: #4698ca;
    border-radius: 50px;
    font: normal normal bold 18px/40px quicksand;
    letter-spacing: 0;
    color: #fff;
    text-transform: uppercase;
    padding: 5px 110px;
  }

  iframe {
    width: 100%;
    height: 485px;
  }
}

/* footer */
.footer {
  background: #37b8f8;
  color: #fff;
  padding-top: 0;
  border: 0;
}

.footer * {
  font-size: 16px;
  letter-spacing: 0.028em;
  font-family: quicksand;
}

.footer .footer__title {
  color: #76574b !important;
  font-family: quicksand;
  font-weight: 800;
  font-size: 18px;
  text-transform: uppercase;
  letter-spacing: 0.15em;
}

.footer__credits,
.footer__credits * {
  color: #fff;
  border-color: #002053;
}

/* correções de blocos quebrados */
.payment__intermediator,
.payment__gateway--123188,
.prices__discount {
  display: none;
}

.payment__gateway--123188:last-child {
  border-bottom: 2px solid #002053;
}

.payment__gateway--123188 {
  border-left: 2px solid #002053;
  border-right: 2px solid #002053;
  background-color: #2d507a;
  color: #fff;

  .payment__back i {
    color: #fff;
  }
}

.quantity-selector__btn-container {
  input {
    background: #f7f7f7;
    border: none;
    height: 49px;
    border-radius: 0;
  }

  .btn {
    background: #f7f7f7;

    &:first-of-type {
      border-top-right-radius: 0;
      border-bottom-right-radius: 0;
    }

    &:last-of-type {
      border-top-left-radius: 0;
      border-bottom-left-radius: 0;
    }
  }
}

/* responsivo */
@media screen and (max-width: 480px) {
  .gallery__item--video {
    font-size: 11px;
    margin-top: -13px !important;
    padding: 8px 12px;
    border-radius: 20px;
    background: #fd8043;
    opacity: 1 !important;
    border: none;
    color: #f8f9fa;
  }

  .top-bar__countdown {
    font-size: 0.7rem;
    font-weight: 500;
  }

  .products-carousel .product-card__buy .btn-primary {
    font-size: 0.7rem;
  }

  .header__container.container-fluid {
    margin-top: 0;
  }
}

@media (min-width: 992px) {
  .gallery__item--video {
    padding: var(--spacer-2) 0;
    font-size: 11px !important;
    background: #f00;
    border-radius: 5px;
    opacity: 1 !important;
    color: #fff;
  }

  .i-play {
    color: #fff !important;
  }

  #header #instant-search .search__box.card {
    left: -30% !important;
  }
}

@media (max-width: 990px) {
  .product-card .product-card__buy {
    flex-direction: column;
  }

  .product-card .product-card__buy > * {
    width: 100% !important;
    justify-content: space-between;
  }

  .product__buy .apx_quantity_selector + span {
    width: 100%;
  }

  .product__buy .apx_quantity_selector + span .btn-primary {
    white-space: nowrap;
    padding-left: 0;
    padding-right: 0;
    width: 100%;
  }

  .product__buy .apx_quantity_selector input {
    width: 130px;
  }
}

@media (min-width: 767px) {
  .direita {
    position: absolute;
    top: 8.5px;
    right: 0.8%;
    text-transform: uppercase;
    display: block !important;
  }

  .direita1 {
    position: absolute;
    top: 8.5px;
    right: 34%;
    text-transform: uppercase;
    display: block !important;
  }

  .direita2 {
    position: absolute;
    top: 8.5px;
    right: 68%;
    text-transform: uppercase;
    display: block !important;
  }

  #clube,
  #cnpj {
    display: none;
  }
}

.direita,
.direita1,
.direita2 {
  display: none;
}
